SELECT P.REPORT_NUMB , P.USER_NUMB , U.USER_NICK , F.FILE_PATH AS PORF_PATH , P.BOOK_NUMB , P.REPORT_GRDE , P.REPORT_CNTN , P.PUBC_YSNO , ( SELECT COUNT(*) FROM TB_RPLIKE L WHERE L.REPORT_NUMB = P.REPORT_NUMB ) AS LIKE_CNT , CASE WHEN EXISTS ( SELECT 1 FROM TB_RPLIKE L WHERE L.REPORT_NUMB = P.REPORT_NUMB AND L.USER_NUMB = #{userNumb} ) THEN #{commYes} ELSE #{commNo} END AS LIKE_YSNO FROM TM_BOOK_INFO B INNER JOIN TM_BOOK_REPORT P ON B.BOOK_NUMB = P.BOOK_NUMB INNER JOIN TM_USERXM U ON P.USER_NUMB = U.USER_NUMB LEFT JOIN TM_FILEXM F ON U.PROF_NUMB = F.FILE_NUMB WHERE P.USER_NUMB != #{userNumb} AND P.PUBC_YSNO = #{commYes}
AND B.BOOK_NUMB = ( SELECT R.BOOK_NUMB FROM TM_BOOK_REPORT R WHERE R.REPORT_NUMB = #{reportNumb} AND R.USER_NUMB = #{userNumb} )
AND B.BOOK_ISBN = #{bookIsbn}
AND 1 = 0
ORDER BY P.REPORT_NUMB DESC


SELECT COUNT(*)
 FROM TM_BOOK_REPORT R
 WHERE R.REPORT_NUMB = #{reportNumb}
   AND (
       R.USER_NUMB = #{userNumb}
    OR R.PUBC_YSNO = #{commYes}
   )

