SELECT #{reportNumb} AS REPORT_NUMB
     , (
       SELECT COUNT(*)
         FROM TB_RPLIKE L
        WHERE L.REPORT_NUMB = #{reportNumb}
       ) AS LIKE_CNT
     , CASE WHEN EXISTS (
       SELECT 1
         FROM TB_RPLIKE L
        WHERE L.REPORT_NUMB = #{reportNumb}
          AND L.USER_NUMB = #{userNumb}
       ) THEN #{commYes} ELSE #{commNo} END AS LIKE_YSNO
  FROM DUAL

